import java.io.*;import java.util.*;class Main{static long count(long[]a){ArrayList<HashMap<Long,Long>>dp=new ArrayList<>();for(long ignored:a)dp.add(new HashMap<>());long ans=0;for(int i=0;i<a.length;i++)for(int j=0;j<i;j++){long d=a[i]-a[j];long prev=dp.get(j).getOrDefault(d,0L);ans+=prev;dp.get(i).put(d,dp.get(i).getOrDefault(d,0L)+prev+1);}return ans;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);long[]a=new long[n];for(int i=0;i<n;i++)a[i]=Long.parseLong(d[idx++]);if(tc>0)out.append("\n\n");out.append(count(a));}System.out.print(out);}}
